// The Amazon Product SDE returns Best Sellers Rank as free text inside
// product_information (e.g. "#1,234 in Electronics ... #5 in Earbuds"),
// not as a numeric field — so we parse the primary rank out of it and
// compare against the rank stored on the previous run.

const numOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = parseFloat(String(v).replace(/[^0-9.]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const getBody = (item) => {
  const resp = item && item.json && item.json.response;
  if (!resp || resp.body === undefined) return {};
  if (typeof resp.body === 'string') {
    try { return JSON.parse(resp.body); } catch (e) { return {}; }
  }
  return resp.body;
};

const row = $('Loop Over Watchlist Items').item.json.fields || {};
const asin = row.asin || '';
const label = row.label || asin;
const threshold = numOrNull(row.rank_threshold);
const hasThreshold = threshold !== null && threshold > 0;
const lastRank = numOrNull(row.last_rank);
const checkedAt = new Date().toISOString();

const body = getBody($input.first());
const info = body.product_information || body.productInformation || {};

// Best Sellers Rank can live under a few key names / shapes — collect candidates.
const candidates = [body.bestsellers_rank, body.best_sellers_rank, body.sales_rank];
for (const [k, v] of Object.entries(info)) {
  if (/best.?sellers?.?rank|bsr/i.test(k)) candidates.push(v);
}
let bsrRaw = '';
for (const c of candidates) {
  if (c !== undefined && c !== null && c !== '') {
    bsrRaw = typeof c === 'string' ? c : JSON.stringify(c);
    break;
  }
}

// Primary rank = first "#<number>"; category = text after the first " in ".
const rankMatch = bsrRaw.match(/#\s*([\d,]+)/);
const rank = rankMatch ? parseInt(rankMatch[1].replace(/,/g, ''), 10) : null;
const catMatch = bsrRaw.match(/#\s*[\d,]+\s+in\s+([^#(\n]+)/i);
const category = catMatch ? catMatch[1].trim() : '';

const delta = (rank !== null && lastRank !== null) ? (rank - lastRank) : null;
const isAlert = hasThreshold && delta !== null && Math.abs(delta) >= threshold;
const direction = delta === null ? 'first reading' : (delta < 0 ? 'improved' : (delta > 0 ? 'dropped' : 'flat'));

return [{
  json: {
    asin,
    label,
    category,
    rank,
    previous_rank: lastRank,
    delta,
    direction,
    rank_found: rank !== null,
    is_alert: isAlert,
    new_last_rank: rank !== null ? rank : lastRank,
    checked_at: checkedAt,
  },
  pairedItem: { item: 0 },
}];

// Collect the ASINs flagged today into one Slack message so a big watchlist
// doesn't produce dozens of pings. Reads the alert rows written to the Rank
// History table earlier in this run.

const alerts = $input.all()
  .map((i) => i.json.fields || {})
  .filter((r) => r && r.asin && r.is_alert);

if (alerts.length === 0) {
  return [{ json: { alertCount: 0, text: '' } }];
}

const rows = alerts.sort(
  (a, b) => Math.abs(Number(b.delta) || 0) - Math.abs(Number(a.delta) || 0),
);

const fmtRank = (n) => (n === null || n === undefined || n === '')
  ? '?'
  : '#' + Number(n).toLocaleString('en-US');

const lines = rows.map((r) => {
  const move = (Number(r.delta) < 0 ? 'up ' : 'down ') + Math.abs(Number(r.delta));
  const cat = r.category ? ' in ' + r.category : '';
  return '- *' + (r.label || r.asin) + '* (' + r.asin + '): '
    + fmtRank(r.previous_rank) + ' to ' + fmtRank(r.rank) + ' (' + move + ')' + cat;
}).join('\n');

const text = ':rotating_light: *Amazon BSR alerts — ' + rows.length + ' product'
  + (rows.length === 1 ? '' : 's') + ' moved beyond threshold today*\n\n'
  + lines + '\n\nFull rank history lives in your Airtable Rank History table.';

return [{ json: { alertCount: rows.length, text } }];
